const body = $json.body || $json;
const clean = (s, n) => (typeof s === 'string' ? s.trim().slice(0, n || 300) : '');

const kind = clean(body.kind, 40);
const business = clean(body.business) || 'the business';
const niche = clean(body.niche) || 'local services';
const city = clean(body.city) || 'Chester County, PA';
const goal = clean(body.goal, 500) || 'get more customers';
const budget = clean(body.budget, 60) || 'small budget';
const extra = clean(body.extra, 1200);

const ctx = `Business: ${business}
Niche: ${niche}
Location: ${city}
Goal: ${goal}
Monthly marketing budget: ${budget}
${extra ? 'Extra context: ' + extra : ''}`;

const T = {
  plan: `You are a senior local-business marketing strategist. Create a concrete 30-day marketing plan.

${ctx}

Include: positioning statement, budget split across channels (real dollar amounts from the stated budget), week-by-week actions (specific, doable by one person), 3 KPIs to track, and the single highest-leverage move to do first. Be specific to the niche and location — no generic fluff.`,
  ad_copy: `You are a direct-response copywriter for local businesses. Write a complete ad copy pack.

${ctx}

Deliver:
1) META — 3 ad variants (angle label, hook line, primary text under 90 words, headline, CTA button choice)
2) GOOGLE RSA — 12 headlines (max 30 chars each) + 4 descriptions (max 90 chars each), high-intent local keywords woven in
3) TIKTOK — 3 video concepts (hook line for first 2 seconds, 15-second script outline, on-screen text)
Make every line specific to the niche and city.`,
  website_copy: `You are a conversion copywriter. Write complete website copy for a one-page site.

${ctx}

Sections: hero (headline + subhead + CTA), 3 service blocks (name + 2-sentence pitch), why-us (3 proof points), short about, FAQ (4 questions with answers), final CTA block. Tone: confident, local, zero corporate fluff. Include a clear pricing signal.`,
  email_sequence: `You are an email marketer. Write a 5-email nurture sequence for new leads.

${ctx}

For each email: send-day (0,2,4,7,11), subject line, body under 120 words, one clear CTA. Email 1 = instant value, 2 = proof/story, 3 = objection killer, 4 = offer with light urgency, 5 = polite breakup that leaves door open.`,
  social_calendar: `You are a social media manager for local businesses. Create a 14-day content calendar.

${ctx}

For each day: platform (FB/IG/TikTok), post type (photo/reel/story/text), caption written out in full, and 5 hashtags. Mix: proof/results, behind-the-scenes, local references, offers (max 3 of 14), and engagement questions.`,
  research: `You are a market researcher. Write a competitor & positioning brief.

${ctx}

Cover: what the top competitors in this niche typically offer and charge, the 3 most common messaging angles in the market, gaps a small operator can exploit, a recommended positioning + price stance for this business, and 5 specific things to verify locally (with how to check each). Be honest about what needs local verification vs general market knowledge.`,
  one_pager: `You are a sales copywriter. Write a sales one-pager this business can send to a prospect.

${ctx}

Structure: bold headline, the problem (2 sentences), the solution (3 bullets with concrete outcomes), how it works (3 steps), simple pricing presentation, guarantee/risk-reversal, and a clear next step. Keep it under 350 words — punchy and skimmable.`
};

const prompt = T[kind];
if (!prompt) return [{ json: { error: 'unknown kind' } }];
return [{ json: { prompt, kind } }];
